const axios = require('axios');
const body = $input.first().json.body || {};
const videoId = body.videoId;

if (!videoId || typeof videoId !== 'string' || !/^[A-Za-z0-9_-]{6,20}$/.test(videoId)) {
  return [{ json: { ok: false, status: 400, error: 'invalid videoId' } }];
}

const YT_UA = 'Mozilla/5.0 (Macintosh; Intel Mac OS X 10_15_4) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/85.0.4183.83 Safari/537.36,gzip(gfe)';
const INNERTUBE_URL = 'https://www.youtube.com/youtubei/v1/player?prettyPrint=false';
const INNERTUBE_CLIENT_VERSION = '20.10.38';
const INNERTUBE_ANDROID_UA = `com.google.android.youtube/${INNERTUBE_CLIENT_VERSION} (Linux; U; Android 14)`;

const debug = {};

async function getTracksInnertube() {
  try {
    const res = await axios.post(INNERTUBE_URL, {
      context: { client: { clientName: 'ANDROID', clientVersion: INNERTUBE_CLIENT_VERSION } },
      videoId,
    }, {
      headers: { 'Content-Type': 'application/json', 'User-Agent': INNERTUBE_ANDROID_UA },
      timeout: 15000,
      validateStatus: () => true,
    });
    debug.innertubeStatus = res.status;
    if (res.status >= 400) { debug.innertubeErr = 'http ' + res.status; return null; }
    const data = res.data;
    debug.playability = (data.playabilityStatus || {}).status;
    debug.playabilityReason = ((data.playabilityStatus || {}).reason || '').slice(0, 200);
    const tracks = data && data.captions && data.captions.playerCaptionsTracklistRenderer && data.captions.playerCaptionsTracklistRenderer.captionTracks;
    debug.tracksFound = Array.isArray(tracks) ? tracks.length : 0;
    return Array.isArray(tracks) && tracks.length ? tracks : null;
  } catch (e) { debug.innertubeCatch = String(e).slice(0, 200); return null; }
}

async function getTracksWatchPage() {
  try {
    const res = await axios.get(`https://www.youtube.com/watch?v=${videoId}`, {
      headers: { 'User-Agent': YT_UA },
      timeout: 15000,
      validateStatus: () => true,
      responseType: 'text',
      transformResponse: [x => x],
    });
    debug.watchStatus = res.status;
    if (res.status >= 400) return null;
    const html = res.data;
    const marker = 'var ytInitialPlayerResponse = ';
    const start = html.indexOf(marker);
    debug.watchMarkerFound = start !== -1;
    if (start === -1) return null;
    const jsonStart = start + marker.length;
    let depth = 0; let end = -1;
    for (let i = jsonStart; i < html.length; i++) {
      if (html[i] === '{') depth++;
      else if (html[i] === '}') { depth--; if (depth === 0) { end = i + 1; break; } }
    }
    if (end === -1) return null;
    const parsed = JSON.parse(html.slice(jsonStart, end));
    const tracks = parsed && parsed.captions && parsed.captions.playerCaptionsTracklistRenderer && parsed.captions.playerCaptionsTracklistRenderer.captionTracks;
    debug.watchTracks = Array.isArray(tracks) ? tracks.length : 0;
    return Array.isArray(tracks) && tracks.length ? tracks : null;
  } catch (e) { debug.watchCatch = String(e).slice(0, 200); return null; }
}

function decodeEntities(s) {
  return s
    .replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"').replace(/&#39;/g, "'").replace(/&apos;/g, "'")
    .replace(/&#x([0-9a-fA-F]+);/g, (_, h) => String.fromCodePoint(parseInt(h, 16)))
    .replace(/&#(\d+);/g, (_, d) => String.fromCodePoint(parseInt(d, 10)));
}

async function fetchCaptionTrack(baseUrl) {
  const res = await axios.get(baseUrl, {
    headers: { 'User-Agent': YT_UA },
    timeout: 15000,
    validateStatus: () => true,
    responseType: 'text',
    transformResponse: [x => x],
  });
  if (res.status >= 400) return null;
  const xml = res.data;
  const pRegex = /<p\s+t="\d+"\s+d="\d+"[^>]*>([\s\S]*?)<\/p>/g;
  const pieces = [];
  let m;
  while ((m = pRegex.exec(xml)) !== null) {
    const inner = m[1];
    let line = '';
    const sRegex = /<s[^>]*>([^<]*)<\/s>/g;
    let sm;
    while ((sm = sRegex.exec(inner)) !== null) line += sm[1];
    if (!line) line = inner.replace(/<[^>]+>/g, '');
    const t = decodeEntities(line).trim();
    if (t) pieces.push(t);
  }
  if (pieces.length === 0) {
    const tRegex = /<text[^>]*>([^<]*)<\/text>/g;
    while ((m = tRegex.exec(xml)) !== null) {
      const t = decodeEntities(m[1]).trim();
      if (t) pieces.push(t);
    }
  }
  return pieces.length ? pieces.join(' ') : null;
}

const tracks = (await getTracksInnertube()) || (await getTracksWatchPage());
if (!tracks || !tracks.length) {
  return [{ json: { ok: false, status: 404, error: 'no captions', videoId, debug } }];
}

const preferred = tracks.find(t => t.languageCode === 'en') || tracks[0];
if (!preferred || !preferred.baseUrl) {
  return [{ json: { ok: false, status: 404, error: 'no caption baseUrl', videoId, debug } }];
}

let transcript = null;
try { transcript = await fetchCaptionTrack(preferred.baseUrl); } catch (e) { debug.captionCatch = String(e).slice(0, 200); transcript = null; }

if (!transcript) {
  return [{ json: { ok: false, status: 404, error: 'empty transcript', videoId, debug } }];
}

return [{ json: { ok: true, status: 200, videoId, transcript, language: preferred.languageCode || 'unknown' } }];
